async (params, browser) => {
  // Open category page
  await browser.open(`https://www.twitch.tv/directory/game/${params.category}`)

  // Wait for streams to load
  await browser.waitForSelector('[class*=\'tower\'] article, [data-a-target=\'directory-first-item\'], [class*=\'stream-card\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll for more streams
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract category streams
  const category_data = await browser.evaluate(`const streams = []; const streamEls = document.querySelectorAll('[class*="tower"] article, [class*="stream-card"], [data-a-target*="card"]'); for (let i = 0; i < Math.min(streamEls.length, 20); i++) { const el = streamEls[i]; const nameEl = el.querySelector('[data-a-target="preview-card-channel-link"], [class*="channel-name"], h3'); const titleEl = el.querySelector('[data-a-target="preview-card-title-link"], [class*="stream-title"], h3 + p'); const viewersEl = el.querySelector('[class*="viewer"], [aria-label*="viewer"]'); const imgEl = el.querySelector('img'); const linkEl = el.querySelector('a[href]'); const tags = []; el.querySelectorAll('[data-a-target="stream-tag"], [class*="tag"] button').forEach(function(tag) { tags.push(tag.textContent.trim()); }); streams.push({ channel: nameEl ? nameEl.textContent.trim() : '', title: titleEl ? titleEl.textContent.trim() : '', viewers: viewersEl ? viewersEl.textContent.trim() : '', tags: tags.slice(0, 5), url: linkEl ? linkEl.href : '', thumbnail: imgEl ? imgEl.getAttribute('src') : '' }); } const categoryTitleEl = document.querySelector('h1, [class*="directory-header"] h1'); const viewerTotalEl = document.querySelector('[class*="total-viewer"], [class*="viewer-count"]'); return { category: '' + params.category + '', title: categoryTitleEl ? categoryTitleEl.textContent.trim() : '', total_viewers: viewerTotalEl ? viewerTotalEl.textContent.trim() : '', stream_count: streams.length, streams: streams, url: window.location.href }`)

  return category_data
}
